I wasn't able to find any implementation of a ThreadPool, except for multiprocessing.pool.ThreadPool, which didn't seem to work for me, so I wrote my own implementation:
```python
class ThreadPool:

    class WorkerThread(threading.Thread):
        count = 0

        def __init__(self, queue):
            threading.Thread.__init__(self, name="WorkerThread{0}".format(self.__class__.count + 1))
            self.__class__.count += 1
            self.queue = queue
            self.daemon = True

            self._running = True
            self.start()

        def run(self):
            while self._running:
                try:
                    task, args, kwargs = self.queue.get(False)
                    task(*args, **kwargs)
                except Queue.Empty:
                    time.sleep(0)
                    pass

        def stop(self):
            self._running = False

    def __init__(self, num_threads=4):
        self.tasks = Queue.Queue()
        self.workers = [self.WorkerThread(self.tasks) for _ in range(num_threads)]

        self.num_threads = num_threads

    def put(self, func, *args, **kwargs):
        self.tasks.put((func, args, kwargs))

    def close(self):
        for worker in self.workers:
            worker.stop()
        for worker in self.workers:
            worker.join()
```
Modified the above script a bit:
```python
import telebot
import threading
import time

def dummy_handler(): # takes roughly .05 seconds on my system.
    x = 0
    for _ in range(1000000):
       x += 1

pool = telebot.ThreadPool()

def test_thread_pool(x):
    for _ in range(x):
        pool.put(dummy_handler)


def test_thread(x):
    for _ in range(x):
        threading.Thread(target=dummy_handler).start()


def timef(func, *args, **kwargs):
    start = time.time()
    func(*args, **kwargs)
    return time.time() - start

for x in [1, 10, 100]:
    print "ThreadPool: {0} tasks, {1} seconds.".format(x, timef(test_thread_pool, x))
    print "Single Threads: {0} tasks, {1} seconds".format(x, timef(test_thread, x))

pool.close()
```
Result:
```
ThreadPool: 1 tasks, 1.21593475342e-05 seconds.
Single Threads: 1 tasks, 0.014475107193 seconds
ThreadPool: 10 tasks, 0.0460138320923 seconds.
Single Threads: 10 tasks, 0.237497091293 seconds
ThreadPool: 100 tasks, 0.00351095199585 seconds.
Single Threads: 100 tasks, 2.13462495804 seconds
```

Though I am not entirely satisfied (can't figure out why 10 tasks takes more time for ThreadPool than 100 tasks), the ThreadPool class shows a big advantage over fire-and-forget Thread creation.

