Following is my refined-tested version, with per-state timeout support, you decide to have it or not:

`import angr, time, threading

import logging
l = logging.getLogger('angr.exploration_techniques.timelimiter')

BEGIN_TIMEKEY = '__tl_begin_time'
STATE_TIMEKEY = '__tl_state_time'

class TimeLimiter(angr.ExplorationTechnique):
    '''
    Time limiter on angr instance or per state in seconds.
    '''

    def __init__(self, max_time, max_state_time=None, drop=True):
        super(TimeLimiter, self).__init__()
        self._max_time = max_time
        self._max_state_time = max_state_time

        self._slot_name = '_DROP' if drop else 'cut'
        self._all_timeouted = False
        self._executor = threading.Thread(target=self._time_monitor)

        if self._max_time is None or self._max_time <= 0:
            l.debug('timelimiter instance timeout is disabled: max time {} is illegal, should be in seconds'.format(self._max_time))
            self._max_time = None
        if self._max_state_time is None or self._max_state_time <= 0:
            l.debug('timelimiter state time limiter is disabled: max time {} is illegal, should be in seconds'.format(self._max_state_time))
            self._max_state_time = None

    def _on_engine_process_pre(self, state):
        state.globals[BEGIN_TIMEKEY] = time.time()

    def _on_engine_process_post(self, state):
        ss = state.inspect.sim_successors
        if len(ss.flat_successors) > 0:
            ctag = time.time()

            for s in ss.flat_successors:
                stag = s.globals.get(BEGIN_TIMEKEY, ctag)
                process_time = ctag - stag
                if process_time > 0:
                    if STATE_TIMEKEY not in s.globals:
                        s.globals[STATE_TIMEKEY] = process_time
                    else:
                        s.globals[STATE_TIMEKEY] += process_time

    def _time_monitor(self):
        time.sleep(self._max_time)
        self._all_timeouted = True
        l.warning('max time limit {} seconds reached'.format(self._max_time))

    def setup(self, simgr):
        if self._max_time:
            self._executor.daemon=True
            self._executor.start()

        if self._max_state_time:
            for state in simgr.active:
                state.inspect.b('engine_process', when=angr.BP_BEFORE, action=self._on_engine_process_pre)
                state.inspect.b('engine_process', when=angr.BP_AFTER, action=self._on_engine_process_post)

    def filter(self, state):
        if self._all_timeouted:
            return self._slot_name

        if self._max_state_time is not None and state.globals.get(STATE_TIMEKEY, 0) >= self._max_state_time:
            l.warning('killing state {} for max time limit {} seconds reached'.format(state, self._max_state_time))
            return self._slot_name
        return None
`

